mapper.select:
SELECT
a.order_no as orderNo,
a.agent_account as agentAccount,
a.agent_name as agentName,
a.adjust_way as adjustWay,
a.order_status as orderStatus,
a.wallet_type as walletType,
a.adjust_type as adjustType,
a.adjust_amount as adjustAmount,
a.apply_time as applyTime,
a.applicant as applicant,
a.apply_reason as applyReason
FROM agent_manual_up_down_record a

    and a.site_code=#{vo.siteCode}
    AND a.adjust_way = 1

        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.agent_account = #{vo.agentAccount}


        AND a.agent_name = #{vo.agentName}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.adjustAmountMin}


        AND a.adjust_amount  <=  #{vo.adjustAmountMax}





        ORDER BY applyTime asc


        ORDER BY applyTime desc



        ORDER BY a.apply_time DESC

SELECT
count(1)
FROM agent_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1

        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.agent_account = #{vo.agentAccount}


        AND a.agent_name = #{vo.agentName}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.adjustAmountMin}


        AND a.adjust_amount  <=  #{vo.adjustAmountMax}

SELECT
'总计' as orderNo,
IFNULL(SUM(a.adjust_amount), 0) as adjustAmount
FROM agent_manual_up_down_record a

    and a.site_code =#{vo.site_code}
    AND a.adjust_way = 1

        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.agent_account = #{vo.agentAccount}


        AND a.agent_name = #{vo.agentName}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.adjustAmountMin}


        AND a.adjust_amount  <=  #{vo.adjustAmountMax}

SELECT
a.id as id,
a.order_no as orderNo,
a.agent_account as agentAccount,
a.agent_name as agentName,
a.adjust_type as adjustType,
a.adjust_amount as adjustAmount,
a.apply_time as applyTime,
a.order_status as orderStatus,
a.lock_status as lockStatus,
IF(a.locker = #{adminName}, -1, 1) as lockStatus1,
a.locker as locker,
a.applicant as applicant,
a.one_reviewer as oneReviewer
FROM agent_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1


            AND a.order_status in (0,1)


            AND a.order_status in (3,4)



        AND a.apply_time  >=  #{vo.applyTimeStart}


        AND a.apply_time  <=  #{vo.applyTimeEnd}


        AND a.order_no = #{vo.orderNo}


        AND a.lock_status = #{vo.lockStatus}


        AND a.locker = #{vo.locker}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount >= #{vo.adjustAmtMin}


        AND a.adjust_amount <= #{vo.adjustAmtMax}


ORDER BY lockStatus1 ASC, a.lock_status ASC, a.apply_time ASC

SELECT
a.id as id,
a.order_no as orderNo,
a.agent_account as agentAccount,
a.agent_name as agentName,
a.wallet_type as walletType,
a.order_status as orderStatus,
a.adjust_type as adjustType,
a.adjust_amount as adjustAmount,
a.apply_time as applyTime,
a.one_reviewer as oneReviewer,
a.two_reviewer as twoReviewer,
a.one_review_finish_time as oneReviewFinishTime,
a.two_review_finish_time as twoReviewFinishTime,
a.one_review_start_time as oneReviewStartTime,
a.two_review_start_time as twoReviewStartTime,
a.one_review_remark as oneReviewRemark,
a.two_review_remark as twoReviewRemark
FROM agent_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1

        And a.review_operation = #{vo.reviewOperation}


        AND a.apply_time  >=  #{vo.applyTimeStart}


        AND a.apply_time  <=  #{vo.applyTimeEnd}


        and a.one_review_finish_time  >=  #{vo.auditTimeStart}



        and a.one_review_finish_time  <=  #{vo.auditTimeEnd}


        and a.wallet_type = #{vo.walletType}


        and a.adjust_type = #{vo.adjustType}


        AND a.order_no = #{vo.orderNo}


        AND a.agent_account = #{vo.agentAccount}


        AND a.order_status = #{vo.orderStatus}


        AND a.one_reviewer = #{vo.oneReviewer}


ORDER BY a.updated_time DESC

SELECT
count(1)
FROM agent_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 1

        And a.review_operation = #{vo.reviewOperation}


        AND a.apply_time  >=  #{vo.applyTimeStart}


        AND a.apply_time  <=  #{vo.applyTimeEnd}


        and a.one_review_finish_time  >=  #{vo.auditTimeStart}



        and a.one_review_finish_time  <=  #{vo.auditTimeEnd}


        and a.wallet_type = #{vo.walletType}


        and a.adjust_type = #{vo.adjustType}


        AND a.order_no = #{vo.orderNo}


        AND a.agent_account = #{vo.agentAccount}


        AND a.order_status = #{vo.orderStatus}


ORDER BY a.updated_time DESC

select sum(t.adjust_amount)
from agent_manual_up_down_record t
left join agent_info u on u.agent_account=t.agent_account
where t.updated_time between #{beginTime} and #{endTime}
and t.adjust_way = #{adjustWay} and t.adjust_type = #{adjustType} and t.site_code = #{siteCode}

    and t.order_status = #{orderStatus}

and u.agent_type in (1,2)

select count(a.person)
from (
select t.agent_account as person
from agent_manual_up_down_record t
left join agent_info u on u.agent_account=t.agent_account
where t.updated_time between #{beginTime} and #{endTime}
and t.adjust_way = #{adjustWay} and t.adjust_type in (2,3,5) and t.site_code = #{siteCode}

    and t.order_status = #{orderStatus}

and u.agent_type in (1,2)
group by t.agent_account
) a

select count(a.person)
from (
select t.agent_account as person
from agent_manual_up_down_record t
left join agent_info u on u.agent_account=t.agent_account
where t.updated_time between #{beginTime} and #{endTime}
and t.adjust_type in (4)

    and t.order_status = #{orderStatus}

and u.agent_type in (1,2)
group by t.agent_account
) a

select t.user_account as person from user_manual_up_down_record t left join user_info u on u.user_account=t.user_account where t.updated_time between #{beginTime} and #{endTime} and t.adjust_type = 2
and t.order_status = #{orderStatus}
and u.account_type in (2,3) group by t.user_account

select t.agent_account
from agent_manual_up_down_record t
left join agent_info u on u.agent_account=t.agent_account
where t.updated_time between #{beginTime} and #{endTime}
and t.adjust_way = #{adjustWay} and t.adjust_type = #{adjustType}

    and t.order_status = #{orderStatus}

and u.agent_type in (1,2)

select m.agent_account
from agent_manual_up_down_record m
left join agent_info u on u.agent_account=m.agent_account
where m.adjust_way=#{adjustWay} and m.adjust_type=#{adjustType}
and m.updated_time between #{beginTime} and #{endTime}
and m.is_big_money = 1

    and m.order_status = #{orderStatus}

and u.agent_type in (1,2)

SELECT DISTINCT user_account
FROM user_manual_up_down_record t
WHERE t.adjust_amount >= #{limitAmount}
AND t.order_status = #{successCode}
AND t.adjust_way = 1
AND t.two_review_finish_time  >=  #{firstMonthStart}
AND t.two_review_finish_time  <=  #{firstMonthEnd}
AND user_account NOT IN (SELECT user_account
FROM vip_award_record
WHERE award_type = #{type}
AND created_time  >=  #{thisMonthStart}
AND created_time  <=  #{thisMonthEnd})

SELECT
"总计" AS orderNo,
IFNULL(SUM(a.adjust_amount),0) AS adjustAmount
FROM
agent_manual_up_down_record a

    and a.site_code = #{vo.siteCode}
    AND a.adjust_way = 2

        AND a.created_time  >=  #{vo.applyStartTime}


        AND a.created_time  <=  #{vo.applyEndTime}


        AND a.order_no = #{vo.orderNo}


        AND a.agent_name = #{vo.agentName}


        AND a.agent_account = #{vo.agentAccount}


        AND a.order_status = #{vo.orderStatus}


        AND a.adjust_type = #{vo.adjustType}


        AND a.adjust_amount  >=  #{vo.minAdjustAmount}


        AND a.adjust_amount  <=  #{vo.maxAdjustAmount}

SELECT a.agent_account AS agentAccount, a.adjust_way adjustWay, a.adjust_amount adjustAmount, a.wallet_type walletType, a.is_big_money as isBigMoney FROM agent_manual_up_down_record a
AND a.adjust_type = 1 AND a.order_status = 3 AND a.balance_change_status = 1 AND a.site_code = #{siteCode}
AND a.agent_account in
#{value}

SELECT id AS id, site_code AS siteCode, agent_id AS agentId, agent_account AS agentAccount, agent_name AS agentName, order_no AS orderNo, wallet_type AS walletType, adjust_way AS adjustWay, adjust_type AS adjustType, adjust_amount AS adjustAmount, certificate_address AS certificateAddress, apply_reason AS applyReason, apply_time AS applyTime, applicant AS applicant, one_review_start_time AS oneReviewStartTime, one_review_finish_time AS oneReviewFinishTime, one_reviewer AS oneReviewer, one_review_remark AS oneReviewRemark, two_review_start_time AS twoReviewStartTime, two_review_finish_time AS twoReviewFinishTime, two_reviewer AS twoReviewer, two_review_remark AS twoReviewRemark, review_operation AS reviewOperation, order_status AS orderStatus, balance_change_status AS balanceChangeStatus, lock_status AS lockStatus, locker AS locker, creator AS creator, updater AS updater, created_time AS createdTime, updated_time AS updatedTime, is_big_money AS isBigMoney, last_operator AS lastOperator, currency_code AS currencyCode, IF(locker = #{vo.adminName}, -1, 1) as lockStatus1 FROM agent_manual_up_down_record
and site_code = #{vo.siteCode}
AND review_operation = #{vo.reviewOperation}
AND apply_time >= #{vo.applyTimeStart}
AND apply_time <= #{vo.applyTimeEnd}
AND order_no = #{vo.orderNo}
AND lock_status = #{vo.lockStatus}
AND locker = #{vo.locker}
AND adjust_type = #{vo.adjustType}
AND adjust_amount >= #{vo.adjustAmtMin}
AND adjust_amount <= #{vo.adjustAmtMax}
AND agent_account = #{vo.agentAccount}
AND wallet_type = #{vo.walletType}
ORDER BY lockStatus1 ASC, lock_status desc, apply_time ASC

select agent_id agentId, SUM(IF(adjust_way = 1, adjust_amount,0)) depositeAmount, SUM(IF(adjust_way = 2, adjust_amount,0)) withdrawAmount from agent_manual_up_down_record
adjust_type = 1 and order_status = 3
and one_review_finish_time >= #{vo.startTime}
AND one_review_finish_time <= #{vo.endTime}
AND agent_id IN
#{value}
group by agent_id
